import java.util.Arrays;

public class ArrayBasics {
    public static void main(String[] args) {
        // Declaration and initialization
        int[] scores = new int[5];          // default: all 0
        int[] primes = {2, 3, 5, 7, 11};   // inline init
        String[] names = new String[3];     // default: all null

        // Traversal and modification
        for (int i = 0; i < primes.length; i++) {
            scores[i % scores.length] += primes[i];
        }
        System.out.println("scores: " + Arrays.toString(scores));

        // Frequency count (character histogram)
        String word = "mississippi";
        int[] freq = new int[26];
        for (char c : word.toCharArray()) {
            freq[c - 'a']++;
        }
        System.out.println("Freq of 's': " + freq['s' - 'a']);  // 4
        System.out.println("Freq of 'i': " + freq['i' - 'a']);  // 4

        // Copy and sort
        int[] copy = Arrays.copyOf(primes, primes.length);
        Arrays.sort(copy);  // already sorted, but demo
        System.out.println("Sorted copy: " + Arrays.toString(copy));

        // Binary search (array must be sorted)
        int idx = Arrays.binarySearch(copy, 5);
        System.out.println("Index of 5: " + idx);  // 2
    }
}

