import java.util.Arrays;

public class MatrixMultiply {
    // Multiply two matrices A (m×k) × B (k×n) → result (m×n)
    public static int[][] multiply(int[][] A, int[][] B) {
        int m = A.length, k = A[0].length, n = B[0].length;
        int[][] result = new int[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int p = 0; p < k; p++) {
                    result[i][j] += A[i][p] * B[p][j];
                }
            }
        }
        return result;
    }

    public static void print(int[][] M) {
        for (int[] row : M) System.out.println(Arrays.toString(row));
    }

    public static void main(String[] args) {
        int[][] A = {{1, 2}, {3, 4}, {5, 6}};  // 3×2
        int[][] B = {{7, 8, 9}, {10, 11, 12}}; // 2×3
        int[][] C = multiply(A, B);             // result: 3×3
        print(C);
        // [27, 30, 33]
        // [61, 68, 75]
        // [95, 106, 117]

        // Jagged array: each row different length
        int[][] triangle = new int[4][];
        for (int i = 0; i < 4; i++) {
            triangle[i] = new int[i + 1];
            Arrays.fill(triangle[i], i + 1);
        }
        System.out.println("\nJagged:");
        print(triangle);
    }
}

public class PrefixSum {
    private final int[] prefix;

    public PrefixSum(int[] arr) {
        prefix = new int[arr.length + 1];
        for (int i = 0; i < arr.length; i++) {
            prefix[i + 1] = prefix[i] + arr[i];
        }
    }

    // Sum of arr[left..right] inclusive in O(1)
    public int rangeSum(int left, int right) {
        return prefix[right + 1] - prefix[left];
    }

    public static void main(String[] args) {
        int[] arr = {3, 1, 4, 1, 5, 9, 2, 6};
        PrefixSum ps = new PrefixSum(arr);

        System.out.println(ps.rangeSum(0, 3));  // 3+1+4+1 = 9
        System.out.println(ps.rangeSum(2, 6));  // 4+1+5+9+2 = 21
        System.out.println(ps.rangeSum(0, 7));  // sum of all = 31

        // Find max sum subarray of length k using sliding window on prefix
        int k = 3;
        int maxSum = ps.rangeSum(0, k - 1);
        for (int i = k; i < arr.length; i++) {
            int windowSum = ps.rangeSum(i - k + 1, i);
            if (windowSum > maxSum) maxSum = windowSum;
        }
        System.out.println("Max sum of " + k + " consecutive: " + maxSum);  // 17
    }
}

import java.util.*;

public class ArraysUtility {
    public static void main(String[] args) {
        // --- Sort ---
        int[] arr = {5, 2, 8, 1, 9, 3};
        Arrays.sort(arr);                    // dual-pivot quicksort, in-place
        System.out.println(Arrays.toString(arr));  // [1, 2, 3, 5, 8, 9]

        // Sort with range
        int[] partial = {5, 2, 8, 1, 9, 3};
        Arrays.sort(partial, 1, 4);          // sort indices 1 to 3 inclusive
        System.out.println(Arrays.toString(partial)); // [5, 1, 2, 8, 9, 3]

        // --- Binary Search ---
        int pos = Arrays.binarySearch(arr, 8);
        System.out.println("8 at index: " + pos);  // 4
        int missing = Arrays.binarySearch(arr, 4);
        System.out.println("4 not found: " + missing); // negative = -(insertion point)-1

        // --- Fill ---
        int[] filled = new int[5];
        Arrays.fill(filled, 7);
        System.out.println(Arrays.toString(filled)); // [7, 7, 7, 7, 7]

        // --- Compare ---
        int[] a = {1, 2, 3};
        int[] b = {1, 2, 3};
        int[] c = {1, 2, 4};
        System.out.println(Arrays.equals(a, b));     // true
        System.out.println(Arrays.equals(a, c));     // false
        System.out.println(Arrays.compare(a, c));    // negative (3 < 4)

        // --- 2D equals ---
        int[][] m1 = {{1,2},{3,4}};
        int[][] m2 = {{1,2},{3,4}};
        System.out.println(Arrays.deepEquals(m1, m2));  // true
        System.out.println(Arrays.deepToString(m1));    // [[1, 2], [3, 4]]
    }
}

public class SlidingWindow {
    // Fixed-size sliding window
    public static int maxSumFixed(int[] arr, int k) {
        if (arr.length < k) throw new IllegalArgumentException();
        // Build first window
        int windowSum = 0;
        for (int i = 0; i < k; i++) windowSum += arr[i];
        int maxSum = windowSum;
        // Slide the window
        for (int i = k; i < arr.length; i++) {
            windowSum += arr[i];        // add new element
            windowSum -= arr[i - k];   // remove oldest element
            maxSum = Math.max(maxSum, windowSum);
        }
        return maxSum;
    }

    // Variable-size sliding window: longest subarray with sum <= target
    public static int longestSubarrayWithSumAtMost(int[] arr, int target) {
        int left = 0, sum = 0, maxLen = 0;
        for (int right = 0; right < arr.length; right++) {
            sum += arr[right];          // expand window
            while (sum > target) {
                sum -= arr[left++];    // shrink from left
            }
            maxLen = Math.max(maxLen, right - left + 1);
        }
        return maxLen;
    }

    public static void main(String[] args) {
        int[] arr = {2, 1, 5, 1, 3, 2};
        System.out.println(maxSumFixed(arr, 3));             // 9 (5+1+3)
        System.out.println(longestSubarrayWithSumAtMost(arr, 7)); // 4 (2,1,3,2 ... wait, 1,5,1=7 len=3)
    }
}

