    public int[] minMax(int[] nums) {
        if (nums.length == 0) throw new IllegalArgumentException();
        int min = nums[0], max = nums[0];
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] < min) min = nums[i];
            if (nums[i] > max) max = nums[i];
        }
        return new int[]{min, max};
    }
}

