public class Solution {
    public int secondLargest(int[] nums) {
        int max = Integer.MIN_VALUE;
        int second = Integer.MIN_VALUE;
        for (int n : nums) {
            if (n > max) {
                second = max;
                max = n;
            } else if (n > second && n != max) {
                second = n;
            }
        }
        return second == Integer.MIN_VALUE ? -1 : second;
    }
}

