public class Solution {
    private int lower, upper;
    private long[] temp;

    public int countRangeSum(int[] nums, int lower, int upper) {
        this.lower = lower; this.upper = upper;
        int n = nums.length;
        long[] prefix = new long[n + 1];
        for (int i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
        temp = new long[n + 1];
        return mergeCount(prefix, 0, n + 1);
    }

    private int mergeCount(long[] arr, int lo, int hi) {
        if (hi - lo <= 1) return 0;
        int mid = (lo + hi) / 2;
        int count = mergeCount(arr, lo, mid) + mergeCount(arr, mid, hi);
        int j = mid, k = mid;
        for (int i = lo; i < mid; i++) {
            while (j < hi && arr[j] - arr[i] < lower) j++;
            while (k < hi && arr[k] - arr[i] <= upper) k++;
            count += k - j;
        }
        // merge step
        int p = lo, q = mid, r = lo;
        while (p < mid && q < hi)
            temp[r++] = arr[p] <= arr[q] ? arr[p++] : arr[q++];
        while (p < mid) temp[r++] = arr[p++];
        while (q < hi)  temp[r++] = arr[q++];
        System.arraycopy(temp, lo, arr, lo, hi - lo);
        return count;
    }
}
